const { event, data } = context;
if (event !== 'ticket.resolved') return;
const cfg = cliaas.config;
const excludeTags = cfg.excludeTags || [];
if (data.tags && data.tags.some(t => excludeTags.includes(t))) return;
const delay = cfg.delayMinutes || 60;
cliaas.log.info(`Scheduling CSAT survey for ticket ${data.ticketId} in ${delay} minutes`);
